request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?message ?messageName ?choreoName ?modelId WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId ?modelId .
  FILTER(?modelId = "2aa476e4bbdf451083ec316570f7a3be")

  ?defs tai:belongsTo ?model .
  ?choreo tai:belongsTo ?defs .

  ?message a bboExt:Message ;
           tai:belongsTo ?choreo .

  OPTIONAL { ?message bbo:name ?messageName . }
  OPTIONAL { ?choreo bbo:name ?choreoName . }
}
ORDER BY ?messageName
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?normId ?origId ?orgId WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:normalizedId ?normId . }
  OPTIONAL { ?model tai:originalId ?origId . }
  OPTIONAL { ?model tai:belongsTo ?org .
             ?org tai:organizationId ?orgId . }
  FILTER(
    (?normId = "2aa476e4bbdf451083ec316570f7a3be") ||
    (?origId = "2aa476e4bbdf451083ec316570f7a3be") ||
    (STR(?model) = "http://www.onto-bpo.eu/resource/" )
  )
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?choreo ?choreoName
                (COUNT(DISTINCT ?msg) AS ?messageCount)
WHERE {
  ?model a bboExt:Model ;
         tai:originalId "2aa476e4bbdf451083ec316570f7a3be" ;
         tai:belongsTo ?org .
  ?defs tai:belongsTo ?model .
  ?choreo tai:belongsTo ?defs .
  OPTIONAL {
    ?msg a bboExt:Message ;
         tai:belongsTo ?choreo .
  }
  OPTIONAL { ?choreo bbo:name ?choreoName . }
}
GROUP BY ?choreo ?choreoName
ORDER BY DESC(?messageCount)
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?msgFlow ?msgFlowName ?sourceId ?targetId ?sourceName ?targetName ?choreoName WHERE {
  ?model a bboExt:Model ;
         tai:originalId "2aa476e4bbdf451083ec316570f7a3be" ;
         tai:belongsTo ?org .
  ?defs tai:belongsTo ?model .
  ?choreo tai:belongsTo ?defs .
  OPTIONAL { ?choreo bbo:name ?choreoName . }

  ?msgFlow a bboExt:MessageFlow ;
           tai:belongsTo ?choreo .
  OPTIONAL { ?msgFlow bbo:name ?msgFlowName . }
  ?msgFlow bboExt:sourceRef ?sourceId ;
           bboExt:targetRef ?targetId .

  OPTIONAL {
    ?srcElem tai:belongsTo ?choreo ;
             bbo:id ?sourceId .
    OPTIONAL { ?srcElem bbo:name ?sourceName . }
  }
  OPTIONAL {
    ?tgtElem tai:belongsTo ?choreo ;
             bbo:id ?targetId .
    OPTIONAL { ?tgtElem bbo:name ?targetName . }
  }
}
ORDER BY ?msgFlowName
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?msgFlow ?msgFlowName ?choreoName
       ?sourceId ?sourceName
       ?targetId ?targetName
WHERE {
  ?model a bboExt:Model ;
         tai:originalId "2aa476e4bbdf451083ec316570f7a3be" ;
         tai:belongsTo ?org .
  ?defs tai:belongsTo ?model .
  ?choreo tai:belongsTo ?defs .
  OPTIONAL { ?choreo bbo:name ?choreoName . }

  ?msgFlow a bboExt:MessageFlow ;
           tai:belongsTo ?choreo ;
           bboExt:sourceRef ?sourceId ;
           bboExt:targetRef ?targetId .
  OPTIONAL { ?msgFlow bbo:name ?msgFlowName . }

  OPTIONAL {
    ?srcElem tai:belongsTo ?choreo ;
             bbo:id ?sourceId .
    OPTIONAL { ?srcElem bbo:name ?sourceName . }
  }
  OPTIONAL {
    ?tgtElem tai:belongsTo ?choreo ;
             bbo:id ?targetId .
    OPTIONAL { ?tgtElem bbo:name ?targetName . }
  }

  BIND(COALESCE(?sourceName, ?sourceId) AS ?sourceLabel)
  BIND(COALESCE(?targetName, ?targetId) AS ?targetLabel)
  FILTER( !(BOUND(?sourceLabel) && BOUND(?targetLabel)) || true )
}
ORDER BY ?msgFlowName
LIMIT 25
